import React, { useState, useEffect, useCallback, forwardRef, useImperativeHandle } from "react";

const TextRotate = forwardRef(
  (
    {
      texts,
      rotationInterval = 2000,
      auto = true,
      loop = true,
      onNext,
      mainClassName = "",
      splitLevelClassName = "",
      elementLevelClassName = "",
    },
    ref
  ) => {
    const [currentTextIndex, setCurrentTextIndex] = useState(0);
    const [isAnimating, setIsAnimating] = useState(false);
    const [displayText, setDisplayText] = useState(texts[0] || "");

    // Helper function to handle index changes
    const handleIndexChange = useCallback((newIndex) => {
      setIsAnimating(true);
      setCurrentTextIndex(newIndex);
      if (onNext) onNext(newIndex);

      // Update display text with animation effect
      setTimeout(() => {
        setDisplayText(texts[newIndex]);
        setTimeout(() => {
          setIsAnimating(false);
        }, 300);
      }, 150);
    }, [texts, onNext]);

    const next = useCallback(() => {
      const nextIndex = currentTextIndex === texts.length - 1
        ? (loop ? 0 : currentTextIndex)
        : currentTextIndex + 1;

      if (nextIndex !== currentTextIndex) {
        handleIndexChange(nextIndex);
      }
    }, [currentTextIndex, texts.length, loop, handleIndexChange]);

    const previous = useCallback(() => {
      const prevIndex = currentTextIndex === 0
        ? (loop ? texts.length - 1 : currentTextIndex)
        : currentTextIndex - 1;

      if (prevIndex !== currentTextIndex) {
        handleIndexChange(prevIndex);
      }
    }, [currentTextIndex, texts.length, loop, handleIndexChange]);

    const jumpTo = useCallback((index) => {
      const validIndex = Math.max(0, Math.min(index, texts.length - 1));
      if (validIndex !== currentTextIndex) {
        handleIndexChange(validIndex);
      }
    }, [texts.length, currentTextIndex, handleIndexChange]);

    const reset = useCallback(() => {
      if (currentTextIndex !== 0) {
        handleIndexChange(0);
      }
    }, [currentTextIndex, handleIndexChange]);

    // Expose all navigation functions via ref
    useImperativeHandle(ref, () => ({
      next,
      previous,
      jumpTo,
      reset,
    }), [next, previous, jumpTo, reset]);

    // Auto rotation effect
    useEffect(() => {
      if (!auto) return;
      const intervalId = setInterval(next, rotationInterval);
      return () => clearInterval(intervalId);
    }, [next, rotationInterval, auto]);

    // Split text into characters for animation
    const splitIntoCharacters = (text) => {
      if (typeof Intl !== "undefined" && "Segmenter" in Intl) {
        const segmenter = new Intl.Segmenter("en", { granularity: "grapheme" });
        return Array.from(segmenter.segment(text), ({ segment }) => segment);
      }
      return Array.from(text);
    };

    const characters = splitIntoCharacters(displayText);

    return (
      <span className={`inline-flex flex-wrap whitespace-pre-wrap ${mainClassName}`}>
        <span className="sr-only">{displayText}</span>
        <span aria-hidden="true" className="inline-flex flex-wrap">
          {characters.map((char, index) => (
            <span
              key={index}
              className={`
                inline-block transition-all duration-300 ease-in-out
                ${isAnimating ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}
                ${splitLevelClassName}
                ${elementLevelClassName}
              `}
              style={{
                transitionDelay: isAnimating ? `${index * 30}ms` : '0ms',
              }}
            >
              {char === ' ' ? '\u00A0' : char}
            </span>
          ))}
        </span>
      </span>
    );
  }
);

TextRotate.displayName = "TextRotate";

export { TextRotate };
